def measure_completeness(collection) -> dict:
    """
    Returns the completeness rate across all chunks in the collection.
    Required fields: source_id, classification, acl, ingest_timestamp, content_hash.
    """
    required = {"source_id", "classification", "acl", "ingest_timestamp", "content_hash"}
    results = collection.get(include=["metadatas"])
    total = len(results["ids"])
    complete = 0
    missing_by_field: dict[str, int] = {f: 0 for f in required}

    for meta in results["metadatas"]:
        chunk_missing = [f for f in required if not meta.get(f)]
        if not chunk_missing:
            complete += 1
        for f in chunk_missing:
            missing_by_field[f] += 1

    return {
        "total_chunks": total,
        "complete_chunks": complete,
        "completeness_rate": round(complete / total * 100, 2) if total else 0,
        "missing_by_field": missing_by_field,
        "threshold_met": (complete / total >= 0.98) if total else False,
    }

from datetime import datetime, timezone, timedelta
import json

SOURCE_REFRESH_POLICY = {
    "legal-policy-docs":      timedelta(days=90),
    "product-pricing":        timedelta(days=7),
    "hr-handbook":            timedelta(days=180),
    "compliance-runbooks":    timedelta(days=30),
}

def measure_freshness(collection) -> dict:
    results = collection.get(include=["metadatas"])
    now = datetime.now(timezone.utc)
    stale_sources = []
    seen = set()

    for meta in results["metadatas"]:
        src = meta.get("source_id", "")
        if src in seen:
            continue
        seen.add(src)
        policy = SOURCE_REFRESH_POLICY.get(src)
        if not policy:
            continue   # no policy declared — skip
        ts = meta.get("ingest_timestamp", "")
        if not ts:
            stale_sources.append({"source_id": src, "reason": "no ingest timestamp"})
            continue
        age = now - datetime.fromisoformat(ts.rstrip("Z")).replace(tzinfo=timezone.utc)
        if age > policy:
            stale_sources.append({
                "source_id": src,
                "age_days": age.days,
                "max_days": policy.days,
            })

    return {
        "sources_checked": len(seen),
        "stale_sources": stale_sources,
        "threshold_met": len(stale_sources) == 0,
    }
